use serde_json::Value;
use std::io::{Read, Write};
use std::net::{Ipv4Addr, TcpListener, TcpStream, UdpSocket};
use std::process::{Child, Command, Stdio};
use std::time::{Duration, Instant};

const ADVERTISE_GROUP: &str = "239.69.0.69";

struct ChildGuard {
    child: Child,
}

impl Drop for ChildGuard {
    fn drop(&mut self) {
        let _ = self.child.kill();
        let _ = self.child.wait();
    }
}

fn bin_path() -> String {
    option_env!("CARGO_BIN_EXE_skymesh-wifi-pluto")
        .map(str::to_string)
        .unwrap_or_else(|| {
            let mut path = std::env::current_exe().expect("current exe");
            path.pop(); // test exe name
            if path.file_name().and_then(|n| n.to_str()) == Some("deps") {
                path.pop();
            }
            path.push("skymesh-wifi-pluto");
            path.display().to_string()
        })
}

fn free_tcp_port() -> u16 {
    TcpListener::bind("127.0.0.1:0")
        .expect("bind ephemeral tcp")
        .local_addr()
        .expect("ephemeral tcp addr")
        .port()
}

fn free_udp_port() -> u16 {
    UdpSocket::bind("127.0.0.1:0")
        .expect("bind ephemeral udp")
        .local_addr()
        .expect("ephemeral udp addr")
        .port()
}

fn start_endpoint(http_port: u16, advertise_port: u16) -> Result<ChildGuard, String> {
    let child = Command::new(bin_path())
        .args([
            "--http-bind",
            &format!("127.0.0.1:{http_port}"),
            "--public-host",
            "127.0.0.1",
            "--advertise-group",
            ADVERTISE_GROUP,
            "--advertise-port",
            &advertise_port.to_string(),
            "--advertise-interval-ms",
            "100",
            "--node-id",
            "skymesh-itest",
        ])
        .stdin(Stdio::null())
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .spawn()
        .map_err(|e| format!("spawn skymesh-wifi-pluto failed: {e}"))?;
    Ok(ChildGuard { child })
}

fn http_json(port: u16, method: &str, path: &str, body: Option<&str>) -> Result<Value, String> {
    let mut stream =
        TcpStream::connect(("127.0.0.1", port)).map_err(|e| format!("connect failed: {e}"))?;
    stream
        .set_read_timeout(Some(Duration::from_secs(2)))
        .map_err(|e| format!("set read timeout failed: {e}"))?;
    let body = body.unwrap_or("");
    let request = format!(
        "{method} {path} HTTP/1.1\r\nHost: 127.0.0.1\r\nContent-Type: application/json\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{body}",
        body.len()
    );
    stream
        .write_all(request.as_bytes())
        .map_err(|e| format!("write request failed: {e}"))?;
    let mut response = String::new();
    stream
        .read_to_string(&mut response)
        .map_err(|e| format!("read response failed: {e}"))?;
    let (_, payload) = response
        .split_once("\r\n\r\n")
        .ok_or_else(|| format!("malformed HTTP response: {response:?}"))?;
    serde_json::from_str(payload).map_err(|e| format!("invalid response json: {e}: {payload}"))
}

fn wait_for_http(port: u16) -> Result<(), String> {
    let deadline = Instant::now() + Duration::from_secs(5);
    let mut last_error = String::new();
    while Instant::now() < deadline {
        match http_json(port, "GET", "/healthz", None) {
            Ok(value) if value["ok"] == true => return Ok(()),
            Ok(value) => last_error = format!("unexpected healthz: {value}"),
            Err(e) => last_error = e,
        }
        std::thread::sleep(Duration::from_millis(50));
    }
    Err(last_error)
}

#[test]
fn endpoint_serves_http_and_refuses_tx_without_enable_flag() {
    let http_port = free_tcp_port();
    let advertise_port = free_udp_port();
    let _child = start_endpoint(http_port, advertise_port).expect("start endpoint");
    wait_for_http(http_port).expect("endpoint became reachable");

    let adv = http_json(http_port, "GET", "/advertisement", None).expect("advertisement");
    assert_eq!(
        adv["schema_version"],
        "gnosis.skymesh.wifi-pluto.advertisement.v1"
    );
    assert_eq!(adv["node_id"], "skymesh-itest");
    assert_eq!(adv["http_url"], format!("http://127.0.0.1:{http_port}"));
    assert_eq!(adv["tx_enabled"], false);

    let iq_path =
        std::env::temp_dir().join(format!("skymesh-pluto-itest-{}.i16", std::process::id()));
    std::fs::write(&iq_path, []).expect("write empty iq file");
    let body = format!(
        r#"{{"iq_path":"{}","preflight_only":true,"tx_lo_hz":433920000}}"#,
        iq_path.display()
    );
    let tx = http_json(http_port, "POST", "/pluto/transmit", Some(&body)).expect("tx dry run");
    let _ = std::fs::remove_file(&iq_path);
    assert_eq!(tx["executed"], false);
    assert_eq!(tx["txEnabled"], false);
    assert_eq!(
        tx["reason"],
        "start with --enable-tx to execute Pluto transmit"
    );
    assert!(tx["setup"].is_array());
    assert!(tx["writedev"].is_array());
}

#[test]
fn host_os_can_receive_wifi_multicast_advertisement_when_supported() {
    let http_port = free_tcp_port();
    let advertise_port = free_udp_port();
    let socket = match UdpSocket::bind(("0.0.0.0", advertise_port)) {
        Ok(socket) => socket,
        Err(e) => {
            eprintln!("skipping multicast visibility test: UDP bind unsupported: {e}");
            return;
        }
    };
    if let Err(e) = socket.join_multicast_v4(
        &ADVERTISE_GROUP
            .parse::<Ipv4Addr>()
            .expect("multicast group"),
        &Ipv4Addr::UNSPECIFIED,
    ) {
        eprintln!("skipping multicast visibility test: join_multicast_v4 unsupported: {e}");
        return;
    }
    if let Err(e) = socket.set_read_timeout(Some(Duration::from_secs(5))) {
        eprintln!("skipping multicast visibility test: read timeout unsupported: {e}");
        return;
    }

    let _child = start_endpoint(http_port, advertise_port).expect("start endpoint");
    wait_for_http(http_port).expect("endpoint became reachable");

    let deadline = Instant::now() + Duration::from_secs(5);
    let mut buf = [0u8; 4096];
    while Instant::now() < deadline {
        match socket.recv_from(&mut buf) {
            Ok((n, _from)) => {
                if let Ok(value) = serde_json::from_slice::<Value>(&buf[..n]) {
                    if value["schema_version"] == "gnosis.skymesh.wifi-pluto.advertisement.v1"
                        && value["node_id"] == "skymesh-itest"
                        && value["http_url"] == format!("http://127.0.0.1:{http_port}")
                    {
                        return;
                    }
                }
            }
            Err(e)
                if matches!(
                    e.kind(),
                    std::io::ErrorKind::WouldBlock | std::io::ErrorKind::TimedOut
                ) =>
            {
                break;
            }
            Err(e) => {
                let unsupported = matches!(
                    e.kind(),
                    std::io::ErrorKind::AddrNotAvailable
                        | std::io::ErrorKind::NetworkUnreachable
                        | std::io::ErrorKind::PermissionDenied
                        | std::io::ErrorKind::Unsupported
                );
                if unsupported {
                    eprintln!("skipping multicast visibility test: recv unsupported: {e}");
                    return;
                }
                panic!("multicast recv failed: {e}");
            }
        }
    }
    panic!(
        "host OS did not receive skymesh-wifi-pluto multicast advertisement on {ADVERTISE_GROUP}:{advertise_port}"
    );
}

#[test]
fn ap_config_only_writes_visible_skymesh_hostapd_config() {
    let output_path =
        std::env::temp_dir().join(format!("skymesh-hostapd-itest-{}.conf", std::process::id()));
    let output = Command::new(bin_path())
        .args([
            "--ap-mode",
            "--ap-interface",
            "wlan-test0",
            "--ap-ssid",
            "skymesh",
            "--ap-channel",
            "6",
            "--ap-config-out",
            output_path.to_str().expect("utf8 temp path"),
            "--ap-config-only",
        ])
        .output()
        .expect("run ap config generator");
    assert!(
        output.status.success(),
        "ap config generator failed: {}",
        String::from_utf8_lossy(&output.stderr)
    );
    let rendered = std::fs::read_to_string(&output_path).expect("read hostapd config");
    let _ = std::fs::remove_file(&output_path);
    assert!(rendered.contains("interface=wlan-test0\n"));
    assert!(rendered.contains("ssid=skymesh\n"));
    assert!(rendered.contains("channel=6\n"));
    assert!(rendered.contains("ignore_broadcast_ssid=0\n"));
}
